'use client';

import { useState } from 'react';
import type { Task, TaskStatus } from '@/lib/types';
import { useTasks } from '@/lib/hooks/useTasks';
import { useProject } from '@/context/ProjectContext';
import TaskCard from './TaskCard';
import ActivityLog from './ActivityLog';
import StatusBadge from '@/components/common/StatusBadge';
import Card from '@/components/common/Card';

const STATUS_COLUMNS: { status: TaskStatus; label: string }[] = [
  { status: 'pending', label: 'Pending' },
  { status: 'in_progress', label: 'In Progress' },
  { status: 'testing', label: 'Testing' },
  { status: 'completed', label: 'Completed' },
  { status: 'failed', label: 'Failed' },
];

export default function TaskBoard() {
  const { projectId } = useProject();
  const { tasks, isLoading } = useTasks(projectId);
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64 text-gray-500 dark:text-gray-400">
        Loading tasks...
      </div>
    );
  }

  if (tasks.length === 0) {
    return (
      <Card className="text-center py-12">
        <div className="px-4">
          <svg className="mx-auto h-12 w-12 text-gray-400 dark:text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M9 12h3.75M9 15h3.75M9 18h3.75m3 .75H18a2.25 2.25 0 002.25-2.25V6.108c0-1.135-.845-2.098-1.976-2.192a48.424 48.424 0 00-1.123-.08m-5.801 0c-.065.21-.1.433-.1.664 0 .414.336.75.75.75h4.5a.75.75 0 00.75-.75 2.25 2.25 0 00-.1-.664m-5.8 0A2.251 2.251 0 0113.5 2.25H15a2.25 2.25 0 012.15 1.586m-5.8 0c-.376.023-.75.05-1.124.08C9.095 4.01 8.25 4.973 8.25 6.108V8.25m0 0H4.875c-.621 0-1.125.504-1.125 1.125v11.25c0 .621.504 1.125 1.125 1.125h9.75c.621 0 1.125-.504 1.125-1.125V9.375c0-.621-.504-1.125-1.125-1.125H8.25zM6.75 12h.008v.008H6.75V12zm0 3h.008v.008H6.75V15zm0 3h.008v.008H6.75V18z" />
          </svg>
          <h3 className="mt-3 text-sm font-semibold text-gray-900 dark:text-white">No tasks</h3>
          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
            No L3 tasks found for this project. Tasks appear when L2 delegates work to L3 specialists.
          </p>
        </div>
      </Card>
    );
  }

  return (
    <div className="flex gap-4 h-full">
      {/* Kanban Columns */}
      <div className="flex-1 flex gap-4 overflow-x-auto pb-4">
        {STATUS_COLUMNS.map(col => {
          const columnTasks = tasks.filter(t =>
            col.status === 'in_progress'
              ? t.status === 'in_progress' || t.status === 'starting'
              : t.status === col.status
          );

          return (
            <div key={col.status} className="flex-shrink-0 w-64">
              <div className="flex items-center gap-2 mb-3 px-1">
                <StatusBadge status={col.status} />
                <span className="text-xs text-gray-500 dark:text-gray-400">
                  {columnTasks.length}
                </span>
              </div>
              <div className="space-y-2">
                {columnTasks.map(task => (
                  <TaskCard key={task.id} task={task} onClick={setSelectedTask} />
                ))}
              </div>
            </div>
          );
        })}
      </div>

      {/* Detail Panel */}
      {selectedTask && (
        <div className="w-80 flex-shrink-0 border-l border-gray-200 dark:border-gray-700 pl-4">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-semibold text-gray-900 dark:text-white">Task Detail</h3>
            <button
              onClick={() => setSelectedTask(null)}
              className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
            >
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          <div className="space-y-3">
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400">Task ID</p>
              <p className="text-sm font-mono text-gray-900 dark:text-white">{selectedTask.id}</p>
            </div>
            <div className="flex gap-2">
              <StatusBadge status={selectedTask.status} />
              {selectedTask.skill_hint && (
                <span className="inline-flex items-center px-1.5 py-0.5 rounded text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300">
                  {selectedTask.skill_hint}
                </span>
              )}
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400">Created</p>
              <p className="text-sm text-gray-900 dark:text-white">
                {new Date(selectedTask.created_at * 1000).toLocaleString()}
