            </div>
            {Object.keys(selectedTask.metadata).length > 0 && (
              <div>
                <p className="text-xs text-gray-500 dark:text-gray-400 mb-1">Metadata</p>
                <div className="text-xs font-mono bg-gray-50 dark:bg-gray-900 rounded p-2 space-y-0.5">
